 41→/**
 42→ * Execute a scenario end-to-end.
 43→ * @returns ScenarioExecutionResult
 44→ */
 45→export async function runScenario(
 46→  options: ScenarioRunnerOptions
 47→): Promise<ScenarioExecutionResult> {
 48→  const {
 49→    scenarioId,
 50→    scenarioDir = 'evals/scenarios/case-studies',
 51→    keepResources = false,
 52→    outputPath,
 53→    timeout = 120000,
 54→    target: targetName,
 55→    skipFixtures = false,
 56→    skipCleanup = false,
 57→    cleanupOnFailure = false,
 58→  } = options;
 59→
 60→  // Get test target (default: local)
 61→  const target: TestTarget = targetName
 62→    ? getTestTarget(targetName)
 63→    : DEFAULT_TARGET;
 64→
 65→  console.log(`\n🎯 Test Target: ${target.displayName}`);
 66→
 67→  // Run pre-flight checks for this target
 68→  const prerequisitesResult = await checkPrerequisites(target);
 69→  if (!prerequisitesResult.passed) {
 70→    exitWithPrerequisiteErrors(target, prerequisitesResult);
 71→  }
 72→
 73→  // Load scenario definition
 74→  const scenario = loadScenario(scenarioId, scenarioDir);
 75→
 76→  console.log(`\nRunning scenario: ${scenario.name} (${scenarioId})`);
 77→  console.log(`Prompts: ${scenario.prompts.length}`);
 78→
 79→  const runId = `run-${new Date().toISOString().replace(/[:.]/g, '-').substring(0, 19)}`;
 80→  const sessionId = `session-${runId}`;
 81→  const startTime = Date.now();
 82→
 83→  // Provision fixtures if defined
 84→  let provisionedFixtures;
 85→  let interpolatedScenario = scenario;
 86→
 87→  if (scenario.fixtures && !skipFixtures) {
 88→    console.log('\n🔧 Provisioning fixtures...\n');
 89→    try {
 90→      provisionedFixtures = await setupFixtures(scenario, runId);
 91→
 92→      // Build template context and interpolate prompts
 93→      const fixtureContext = buildFixtureContext(provisionedFixtures, runId);
 94→      interpolatedScenario = interpolateScenario(scenario, fixtureContext);
 95→
 96→      console.log('\n✅ Fixtures provisioned successfully\n');
 97→    } catch (fixtureError) {
 98→      console.error('\n❌ Fixture provisioning failed:', fixtureError);
 99→      throw fixtureError;
100→    }
101→  } else if (scenario.fixtures && skipFixtures) {
102→    console.log('\n⏭️  Skipping fixture provisioning (--skip-fixtures flag)\n');
103→  }
104→
105→  const result: ScenarioExecutionResult = {
106→    scenario_id: scenarioId,
107→    run_id: runId,
108→    executed_at: new Date().toISOString(),
109→    target: target.name,
110→    status: 'success',
111→    tools_called: [],
112→    execution_time_ms: 0,
113→    resources_created: [],
114→    cleanup_performed: false,
115→  };
116→
117→  let fullLogOutput = '';
118→
119→  try {
120→    // Execute prompts sequentially (use interpolated scenario)
121→    for (let i = 0; i < interpolatedScenario.prompts.length; i++) {
122→      const prompt = interpolatedScenario.prompts[i];
123→      console.log(`\nPrompt ${i + 1}/${interpolatedScenario.prompts.length}:`);
124→      console.log(`  "${prompt}"`);
125→
126→      const { toolsCalled, logOutput } = await executePrompt(prompt, timeout);
127→      result.tools_called.push(...toolsCalled);
128→      fullLogOutput += logOutput + '\n';
129→
130→      console.log(`  Tools called: ${toolsCalled.join(', ')}`);
131→    }
132→
133→    // Fetch tool call logs from the appropriate source (target-specific)
134→    console.log(`\n📊 Fetching tool call logs from ${target.logSource}...`);
135→    const logs = await fetchToolCallLogs(target, sessionId, fullLogOutput);
136→    const toolNamesFromLogs = extractToolNames(logs);
137→
138→    if (toolNamesFromLogs.length > 0) {
139→      console.log(`  Tools from logs: ${toolNamesFromLogs.join(', ')}`);
140→      // Use logs as authoritative source if available
141→      result.tools_called = toolNamesFromLogs;
142→    }
143→
144→    // Extract resources created (parse from MCP logs or tool call results)
145→    result.resources_created = extractResourcesFromToolCalls(
146→      result.tools_called,
147→      fullLogOutput
148→    );
149→
150→    // Enhanced state validation (if fixtures were provisioned)
151→    if (provisionedFixtures && !skipFixtures) {
152→      console.log('\n🔍 Validating scenario state...\n');
153→      const stateValidation = await validateScenarioState(scenario, provisionedFixtures);
154→
155→      if (!stateValidation.passed) {
156→        result.status = 'failure';
157→        result.failure_details = {
158→          failed_tool: 'state_validation',
159→          error_message: 'State validation failed',
160→          context: { checks: stateValidation.checks },
161→        };
162→      }
163→    } else {
164→      // Fallback to traditional validation for scenarios without fixtures
165→      if (target.logSource === 'outcome-validation') {
166→        // For mittwald.de: Use outcome validator with `mw` CLI
167→        console.log(`\n🔍 Validating outcome using mw CLI...`);
168→        const outcomeResult = await validateScenarioOutcome(scenario, target);
169→        result.outcome_validation = {
170→          all_passed: outcomeResult.allPassed,
171→          checks: outcomeResult.checks,
172→          errors: outcomeResult.errors,
173→          expected_tools: outcomeResult.expectedTools,
174→        };
175→
176→        if (!outcomeResult.allPassed) {
177→          result.status = 'failure';
178→          result.failure_details = {
179→            failed_tool: 'outcome_validation',
180→            error_message: `Outcome validation failed: ${outcomeResult.errors.join(', ')}`,
181→            context: { validation_checks: outcomeResult.checks },
182→          };
183→        }
184→
185→        // For mittwald.de, use expected_tools if outcome passed
186→        if (outcomeResult.allPassed && outcomeResult.expectedTools) {
187→          result.tools_called = outcomeResult.expectedTools;
188→        }
189→      } else {
190→        // For local/Fly.io: Use traditional validation
191→        const validation = validateOutcome(scenario, result);
192→        if (!validation.valid) {
193→          console.error('Validation errors:', validation.errors);
194→          result.status = 'failure';
195→          result.failure_details = {
196→            failed_tool: 'validation',
197→            error_message: `Validation failed: ${validation.errors.join(', ')}`,
198→            context: { validation_errors: validation.errors },
199→          };
200→        }
201→      }
202→    }
203→
204→    // Perform cleanup
205→    const shouldCleanup =
206→      !keepResources &&
207→      !skipCleanup &&
208→      (result.status === 'success' || cleanupOnFailure);
209→
210→    if (shouldCleanup && provisionedFixtures) {
211→      // Use new fixture cleanup (dependency-aware)
212→      try {
213→        const cleanupResult = await cleanupFixtures(provisionedFixtures, scenario);
214→        result.cleanup_performed = cleanupResult.success;
215→
216→        if (cleanupResult.failed.length > 0) {
217→          result.cleanup_errors = cleanupResult.failed.map(
218→            (f) => `${f.type} ${f.id}: ${f.error}`
219→          );
220→        }
221→      } catch (cleanupError) {
222→        result.cleanup_errors = [
223→          cleanupError instanceof Error
224→            ? cleanupError.message
225→            : String(cleanupError),
226→        ];
227→        console.error('Cleanup failed:', result.cleanup_errors);
228→      }
229→    } else if (!shouldCleanup && scenario.cleanup && result.status === 'success') {
230→      // Fallback to legacy cleanup prompts (for scenarios without fixtures)
231→      console.log('\nPerforming legacy cleanup...');
232→      try {
233→        for (const cleanupPrompt of interpolatedScenario.cleanup || []) {
234→          await executePrompt(cleanupPrompt, timeout);
235→        }
236→        result.cleanup_performed = true;
237→      } catch (cleanupError) {
238→        result.cleanup_errors = [
239→          cleanupError instanceof Error
240→            ? cleanupError.message
241→            : String(cleanupError),
242→        ];
243→        console.error('Cleanup failed:', result.cleanup_errors);
244→      }
245→    } else if (keepResources) {
246→      console.log('\nSkipping cleanup (--keep-resources flag)');
247→    } else if (skipCleanup) {
248→      console.log('\nSkipping cleanup (--skip-cleanup flag)');
249→    } else if (result.status === 'failure' && !cleanupOnFailure) {
250→      console.log('\nSkipping cleanup (scenario failed, use --cleanup-on-failure to force)');
251→    }
252→
253→    if (result.status !== 'failure') {
254→      result.status = 'success';
255→    }
256→  } catch (error) {
257→    result.status = 'failure';
258→    result.failure_details = {
259→      failed_tool: 'unknown', // Extract from error context
260→      error_message: error instanceof Error ? error.message : String(error),
261→      context: {},
262→    };
263→    console.error('Scenario execution failed:', error);
264→  }
265→
266→  result.execution_time_ms = Date.now() - startTime;
267→
268→  // Save result
269→  const resultPath =
270→    outputPath ||
271→    getDefaultResultPath(runId, scenarioId, result.status);
272→  saveResult(result, resultPath);
273→  result.log_file_path = resultPath;
274→
275→  // Update tool validation records
276→  updateValidationRecords(result);
277→
278→  console.log(`\nScenario ${result.status}: ${scenarioId}`);
279→  console.log(`Execution time: ${result.execution_time_ms}ms`);
280→  console.log(`Tools called: ${result.tools_called.length}`);
281→  console.log(`Result saved: ${resultPath}`);
282→
283→  return result;
284→}
