286→/**
287→ * Execute a single prompt via Claude Code CLI.
288→ * @returns Object with tool names called and log output
289→ */
290→async function executePrompt(
291→  prompt: string,
292→  timeout: number
293→): Promise<{ toolsCalled: string[]; logOutput: string }> {
294→  return new Promise((resolve, reject) => {
295→    const toolsCalled: string[] = [];
296→
297→    // Get project root and MCP config path
298→    const projectRoot = process.cwd();
299→    const mcpConfigPath = path.join(projectRoot, '.mcp.json');
300→
301→    // Check if debug mode is enabled
302→    const debugMode = process.env.DEBUG_SCENARIO === 'true';
303→
304→    // Build command args with MCP flags
305→    const args = [
306→      '--print',  // Use --print for non-interactive mode
307→      prompt,
308→      '--mcp-config', mcpConfigPath,
309→      '--allowedTools', 'mcp__mittwald__*',  // Auto-approve all Mittwald tools
310→      '--output-format', 'stream-json',  // Get structured output with tool calls
311→      '--verbose'  // Required for stream-json output
312→    ];
313→
314→    if (debugMode) {
315→      args.push('--debug', 'mcp');
316→    }
317→
318→    // Spawn Claude Code CLI as subprocess with MCP configuration
319→    const child = spawn('claude', args, {
320→      cwd: projectRoot,
321→      stdio: ['ignore', 'pipe', 'pipe'],
322→      timeout,
323→      env: {
324→        ...process.env,
325→        HOME: process.env.HOME,
326→        PATH: process.env.PATH
327→      }
328→    });
329→
330→    let stdout = '';
331→    let stderr = '';
332→
333→    child.stdout?.on('data', (data) => {
334→      stdout += data.toString();
335→    });
336→
337→    child.stderr?.on('data', (data) => {
338→      stderr += data.toString();
339→    });
340→
341→    child.on('close', (code) => {
342→      if (code === 0) {
343→        // Parse tool calls from stdout (MCP logs)
344→        const toolsFromLogs = parseToolCallsFromOutput(stdout);
345→        resolve({ toolsCalled: toolsFromLogs, logOutput: stdout });
346→      } else {
347→        reject(new Error(`Claude CLI exited with code ${code}: ${stderr}`));
348→      }
349→    });
350→
351→    child.on('error', (error) => {
352→      reject(new Error(`Failed to spawn Claude CLI: ${error.message}`));
353→    });
354→
355→    // Timeout handler
356→    setTimeout(() => {
357→      if (!child.killed) {
358→        child.kill();
359→        reject(new Error(`Prompt execution timeout (${timeout}ms)`));
360→      }
361→    }, timeout);
362→  });
363→}
364→
365→/**
366→ * Parse tool calls from Claude CLI output (stream-json format).
367→ * Looks for {"type":"assistant"} messages with tool_use content.
368→ */
369→function parseToolCallsFromOutput(output: string): string[] {
370→  const tools: string[] = [];
371→  const lines = output.split('\n');
372→
373→  for (const line of lines) {
374→    if (!line.trim()) continue;
375→
376→    try {
377→      const json = JSON.parse(line);
378→
379→      // Look for assistant messages with tool_use content
380→      if (json.type === 'assistant' && json.message?.content) {
381→        for (const content of json.message.content) {
382→          if (content.type === 'tool_use' && content.name) {
383→            tools.push(content.name);
384→          }
385→        }
386→      }
387→    } catch {
388→      // Skip non-JSON lines
389→    }
390→  }
391→
392→  return tools;
393→}
