395→/**
396→ * Save scenario execution result to JSON file.
397→ */
398→function saveResult(
399→  result: ScenarioExecutionResult,
400→  filePath: string
401→): void {
402→  const dir = path.dirname(filePath);
403→  if (!fs.existsSync(dir)) {
404→    fs.mkdirSync(dir, { recursive: true });
405→  }
406→
407→  fs.writeFileSync(filePath, JSON.stringify(result, null, 2), 'utf-8');
408→}
