 270→function parseArgs(argv: string[]): RunnerOptions {
 271→  const mcpConfigDefault = toAbsolute('.mcp.json');
 272→  let mcpUrlExplicitlySet = false;
 273→
 274→  const options: RunnerOptions = {
 275→    agents: ['claude'],
 276→    promptDir: toAbsolute('evals/prompts'),
 277→    outputDir: toAbsolute('evals/results/agent-e2e'),
 278→    timeoutMs: DEFAULT_TIMEOUT_MS,
 279→    mcpConfigPath: mcpConfigDefault,
 280→    target: DEFAULT_MCP_TARGET,
 281→    mcpUrl: DEFAULT_MCP_URL,
 282→    skipPreflight: false,
 283→    preflightOnly: false,
 284→    continueOnFailure: true,
 285→    requireCoverage: 100,
 286→    coverageMode: 'all-agents',
 287→    requireSelfAssessment: false,
 288→    cleanupTestProjects: true,
 289→    codexMcpServerName: 'mittwald',
 290→    opencodeModel: process.env.OPENCODE_MODEL || 'opencode/gpt-5-nano',
 291→  };
 292→
 293→  for (const arg of argv) {
 294→    if (!arg.startsWith('--')) {
 295→      throw new Error(`Unknown argument format: ${arg}`);
 296→    }
 297→
 298→    const [rawKey, rawValue] = arg.slice(2).split('=', 2);
 299→    const key = rawKey.trim();
 300→    const value = rawValue?.trim();
 301→
 302→    switch (key) {
 303→      case 'agents':
 304→        if (!value) {
 305→          throw new Error('--agents requires a value');
 306→        }
 307→        options.agents = parseCsv(value).map((agent) => {
 308→          if (!SUPPORTED_AGENTS.includes(agent as AgentName)) {
 309→            throw new Error(
 310→              `Unsupported agent '${agent}'. Supported: ${SUPPORTED_AGENTS.join(', ')}`
 311→            );
 312→          }
 313→          return agent as AgentName;
 314→        });
 315→        break;
 316→      case 'prompt-dir':
 317→        if (!value) throw new Error('--prompt-dir requires a value');
 318→        options.promptDir = toAbsolute(value);
 319→        break;
 320→      case 'output-dir':
 321→        if (!value) throw new Error('--output-dir requires a value');
 322→        options.outputDir = toAbsolute(value);
 323→        break;
 324→      case 'timeout-ms':
 325→        if (!value) throw new Error('--timeout-ms requires a value');
 326→        options.timeoutMs = parseIntArg(value, '--timeout-ms');
 327→        break;
 328→      case 'mcp-config':
 329→        if (!value) throw new Error('--mcp-config requires a value');
 330→        options.mcpConfigPath = toAbsolute(value);
 331→        break;
 332→      case 'target':
 333→        if (!value) throw new Error('--target requires a value');
 334→        if (value !== 'fly' && value !== 'mittwald') {
 335→          throw new Error(
 336→            `Invalid --target '${value}'. Use 'fly' or 'mittwald'`
 337→          );
 338→        }
 339→        options.target = value;
 340→        if (!mcpUrlExplicitlySet) {
 341→          options.mcpUrl = MCP_TARGET_URLS[value];
 342→        }
 343→        break;
 344→      case 'mcp-url':
 345→        if (!value) throw new Error('--mcp-url requires a value');
 346→        mcpUrlExplicitlySet = true;
 347→        options.mcpUrl = value;
 348→        break;
 349→      case 'domains':
 350→        if (!value) throw new Error('--domains requires a value');
 351→        options.domains = new Set(parseCsv(value));
 352→        break;
 353→      case 'tools':
 354→        if (!value) throw new Error('--tools requires a value');
 355→        options.tools = new Set(parseCsv(value).map(normalizeToolName));
 356→        break;
 357→      case 'max-tools':
 358→        if (!value) throw new Error('--max-tools requires a value');
 359→        options.maxTools = parseIntArg(value, '--max-tools');
 360→        break;
 361→      case 'skip-preflight':
 362→        options.skipPreflight = true;
 363→        break;
 364→      case 'preflight-only':
 365→        options.preflightOnly = true;
 366→        break;
 367→      case 'continue-on-failure':
 368→        options.continueOnFailure = true;
 369→        break;
 370→      case 'fail-fast':
 371→        options.continueOnFailure = false;
 372→        break;
 373→      case 'require-coverage':
 374→        if (!value) throw new Error('--require-coverage requires a value');
 375→        options.requireCoverage = parseFloatArg(value, '--require-coverage');
 376→        break;
 377→      case 'coverage-mode':
 378→        if (!value) throw new Error('--coverage-mode requires a value');
 379→        if (value !== 'all-agents' && value !== 'any-agent') {
 380→          throw new Error(
 381→            `Invalid --coverage-mode '${value}'. Use 'all-agents' or 'any-agent'`
 382→          );
 383→        }
 384→        options.coverageMode = value;
 385→        break;
 386→      case 'require-self-assessment':
 387→        options.requireSelfAssessment = true;
 388→        break;
 389→      case 'cleanup-test-projects':
 390→        options.cleanupTestProjects = true;
 391→        break;
 392→      case 'no-cleanup-test-projects':
 393→        options.cleanupTestProjects = false;
 394→        break;
 395→      case 'cleanup-project-prefix':
 396→        if (!value) throw new Error('--cleanup-project-prefix requires a value');
 397→        options.cleanupProjectPrefix = value;
 398→        break;
 399→      case 'codex-mcp-server-name':
 400→        if (!value) throw new Error('--codex-mcp-server-name requires a value');
 401→        options.codexMcpServerName = value;
 402→        break;
 403→      case 'codex-model':
 404→        if (!value) throw new Error('--codex-model requires a value');
 405→        options.codexModel = value;
 406→        break;
 407→      case 'claude-model':
 408→        if (!value) throw new Error('--claude-model requires a value');
 409→        options.claudeModel = value;
 410→        break;
 411→      case 'opencode-model':
 412→        if (!value) throw new Error('--opencode-model requires a value');
 413→        options.opencodeModel = value;
 414→        break;
 415→      default:
 416→        throw new Error(`Unknown flag: --${key}`);
 417→    }
 418→  }
 419→
 420→  if (options.agents.length === 0) {
 421→    throw new Error('At least one agent is required');
 422→  }
 423→
 424→  return options;
 425→}
