 892→function stripAnsi(raw: string): string {
 893→  const esc = String.fromCharCode(27);
 894→  return raw.replace(new RegExp(`${esc}\\[[0-9;]*m`, 'g'), '');
 895→}
 896→
 897→function parseJsonArrayFromOutput(raw: string): unknown[] {
 898→  const cleaned = stripAnsi(raw);
 899→  const start = cleaned.indexOf('[');
 900→  const end = cleaned.lastIndexOf(']');
 901→  if (start < 0 || end < 0 || end <= start) {
 902→    throw new Error('Could not locate JSON array in mw output');
 903→  }
 904→  const jsonText = cleaned.slice(start, end + 1);
 905→  const parsed = JSON.parse(jsonText);
 906→  if (!Array.isArray(parsed)) {
 907→    throw new Error('mw project list output is not a JSON array');
 908→  }
 909→  return parsed;
 910→}
