 82→        path: '/health',
 83→        ts: Date.now(),
 84→        checks: {
 85→          redis: 'unknown',
 86→        },
 87→      });
 88→      return;
 89→    }
 90→
 91→    const redisHealthy = await checkRedisHealth();
 92→    const transport = process.env.ENABLE_HTTPS === 'true' ? 'https' : 'http';
 93→    const statusCode = redisHealthy ? 200 : 503;
 94→    const payload = {
 95→      status: redisHealthy ? 'healthy' : 'unhealthy',
 96→      service: 'mcp-server',
 97→      path: '/health',
 98→      ts: Date.now(),
 99→      transport,
100→      capabilities: {
101→        oauth: true,
102→        mcp: true,
103→      },
104→      checks: {
105→        redis: redisHealthy ? 'up' : 'down',
106→      },
107→    } as const;
108→
109→    const ip = req.ip || req.connection.remoteAddress || 'unknown';
110→    const ua = req.get('User-Agent') || 'unknown';
111→    if (redisHealthy) {
112→      console.log(`❤️  HEALTH → 200 from ${ip} ua=${ua}`);
113→      res.status(statusCode).json(payload);
