109→    const streamMapping = transportAny._streamMapping;
110→    const requestToStreamMapping = transportAny._requestToStreamMapping;
111→    const requestResponseMap = transportAny._requestResponseMap;
112→
113→    if (!streamMapping || !requestToStreamMapping) {
114→      return;
115→    }
116→
117→    const serverAny = sessionInfo.server as unknown as {
118→      _requestHandlerAbortControllers?: Map<unknown, AbortController>;
119→    };
