125→          if (candidateRes === res) {
126→            streamId = candidateStreamId;
127→            break;
128→          }
129→        }
130→
131→        if (!streamId) {
132→          return;
133→        }
134→
135→        const requestIds: unknown[] = [];
136→        for (const [requestId, mappedStreamId] of requestToStreamMapping.entries()) {
137→          if (mappedStreamId === streamId) {
138→            requestIds.push(requestId);
139→          }
140→        }
141→
142→        if (requestIds.length === 0) {
